const rows = items.map(item => item.json);
const header = rows.length ? Object.keys(rows[0]) : [];
const preferred = ['domain', 'website', 'url', 'site', 'homepage'];
const lower = header.map(v => v.toLowerCase());
let urlCol = header[0] || '';
for (const c of preferred) {
  const i = lower.indexOf(c);
  if (i !== -1) { urlCol = header[i]; break; }
}
const formData = $('Form Trigger').first();
const binaryData = formData.binary && formData.binary.Lead_CSV;
const originalName = binaryData ? binaryData.fileName : 'output.csv';
const baseName = originalName.replace(/\.csv$/i, '');
const outputPath = '/tmp/' + baseName + '-results.csv';

return rows.map((row, idx) => {
  let rawUrl = String(row[urlCol] || '').trim();
  if (rawUrl && !/^https?:\/\//i.test(rawUrl)) rawUrl = 'https://' + rawUrl;
  return {
    json: {
      _scrapeUrl: rawUrl,
      _rowIndex: idx,
      _urlColumn: urlCol,
      _outputPath: outputPath,
      _originalHeader: header,
      _originalRow: row
    }
  };
});

const prepItems = $('Prepare URL Items').all();
const SOC = {
  linkedin: /linkedin\.com\/(company|in|school)\//i,
  facebook: /facebook\.com\//i,
  instagram: /instagram\.com\//i,
  twitter: /(twitter\.com|x\.com)\//i,
  tiktok: /tiktok\.com\//i,
  youtube: /(youtube\.com|youtu\.be)\//i,
  pinterest: /pinterest\./i
};
const EMAIL_RE = /[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/g;
const HREF_RE = /href\s*=\s*["']([^"']*?)["']/gi;
const CONTACT_RE = /contact|get-in-touch|support|impressum/i;
const BAD_DOMS = ['sentry.io','wixpress.com'];
const BAD_LOCAL = ['example','test','noreply','no-reply','yourname','username'];

function ok(e) {
  if (!e || !e.includes('@')) return false;
  const p = e.split('@'); if (p.length !== 2) return false;
  const [l, d] = p;
  if (!l || !d || !d.includes('.')) return false;
  if (l.length < 2 || l.length > 64) return false;
  if (BAD_DOMS.some(b => d === b || d.endsWith('.'+b))) return false;
  if (BAD_LOCAL.includes(l)) return false;
  if (/^[a-f0-9]{24,}$/i.test(l)) return false;
  return true;
}
function uniq(a) { return [...new Set((a||[]).filter(Boolean))]; }

const results = [];
for (let i = 0; i < items.length; i++) {
  const orig = prepItems[i] ? prepItems[i].json : {};
  const row = orig._originalRow || {};
  const url = orig._scrapeUrl || '';
  const resp = items[i].json || {};
  let html = '';
  let sc = 'error';

  if (items[i].error || !url) {
    results.push({ json: { ...row, scrape_input_url: url, scrape_status: url ? 'error' : 'no-url', homepage_status_code: 'error',
      scrape_domain:'',contact_page:'',linkedin_urls:'',facebook_urls:'',instagram_urls:'',twitter_urls:'',
      tiktok_urls:'',youtube_urls:'',pinterest_urls:'',emails_found:'',phones_found:'' }});
    continue;
  }

  html = typeof resp === 'string' ? resp : (resp.body || resp.data || '');
  sc = resp.statusCode || resp.status || 200;
  if (typeof html !== 'string') html = '';

  let domain = '';
  try { domain = new URL(url).hostname.replace(/^www\./, ''); } catch {}

  const soc = {};
  for (const k of Object.keys(SOC)) soc[k] = [];
  const emails = [];
  let contactPage = '';

  let m;
  const hre = new RegExp(HREF_RE.source, HREF_RE.flags);
  while ((m = hre.exec(html)) !== null) {
    const h = m[1];
    for (const [k, re] of Object.entries(SOC)) {
      if (re.test(h)) soc[k].push(h.split('?')[0]);
    }
    if (!contactPage && CONTACT_RE.test(h)) contactPage = h;
    if (/^mailto:/i.test(h)) {
      const e = decodeURIComponent(h.replace(/^mailto:/i,'').split('?')[0]).toLowerCase().trim();
      if (ok(e)) emails.push(e);
    }
  }

  const em2 = html.match(EMAIL_RE) || [];
  for (const e of em2) { const c = e.toLowerCase(); if (ok(c)) emails.push(c); }

  const phoneRe = /(?:\+?\d[\d()\s.-]{6,}\d)/g;
  const pm = html.match(phoneRe) || [];
  const phones = uniq(pm.map(p => p.replace(/[^\d+]/g, '')).filter(p => p.replace(/\D/g,'').length >= 10 && p.replace(/\D/g,'').length <= 15));

  results.push({ json: {
    ...row,
    scrape_input_url: url,
    scrape_domain: domain,
    homepage_status_code: sc,
    contact_page: contactPage,
    linkedin_urls: uniq(soc.linkedin).join(' | '),
    facebook_urls: uniq(soc.facebook).join(' | '),
    instagram_urls: uniq(soc.instagram).join(' | '),
    twitter_urls: uniq(soc.twitter).join(' | '),
    tiktok_urls: uniq(soc.tiktok).join(' | '),
    youtube_urls: uniq(soc.youtube).join(' | '),
    pinterest_urls: uniq(soc.pinterest).join(' | '),
    emails_found: uniq(emails).join(' | '),
    phones_found: phones.join(' | '),
    scrape_status: html ? 'ok' : 'no-content'
  }});
}
return results;

// Collect all successfully scraped domains for Enflowpy enrichment
const allItems = items.map(item => item.json);
const domains = [...new Set(
  allItems
    .filter(r => r.scrape_domain && r.scrape_status === 'ok')
    .map(r => r.scrape_domain)
)];

const formData = $('Form Trigger').first();
const binaryData = formData.binary && formData.binary.Lead_CSV;
const filename = binaryData ? binaryData.fileName : 'n8n-upload.csv';
const email = formData.json.enflowEmail || '';
const password = formData.json.enflowPassword || '';

return [{
  json: {
    domains,
    filename,
    email,
    password,
    totalDomains: domains.length,
    scrapedRows: allItems
  }
}];

// Merge Enflowpy job response with scraped data for final CSV output
const collectNode = $('Collect Domains for Enflowpy').first().json;
const enflowResponse = items[0].json || {};
const scrapedRows = collectNode.scrapedRows || [];

// Add Enflowpy job info to each row
const enrichmentId = enflowResponse.enrichmentID || enflowResponse.enrichment_id || '';
const enrichmentStatus = enflowResponse.status || enflowResponse.detail || 'unknown';

return scrapedRows.map(row => ({
  json: {
    ...row,
    enflowpy_job_id: enrichmentId,
    enflowpy_status: enrichmentStatus
  }
}));
